Here are comprehensive unit tests for the `deep_get` function using pytest style, covering happy paths, edge cases, and error cases:

```python
import pytest

def test_deep_get_happy_path():
    """Test normal cases with nested dictionaries."""
    data = {
        'a': {
            'b': {
                'c': 42
            }
        }
    }

    assert deep_get(data, 'a.b.c') == 42
    assert deep_get(data, 'a.b') == {'c': 42}
    assert deep_get(data, 'a') == {'b': {'c': 42}}

def test_deep_get_with_default():
    """Test cases where default value is returned."""
    data = {'a': {'b': 1}}

    assert deep_get(data, 'a.b.c', default=0) == 0
    assert deep_get(data, 'x.y.z', default='not found') == 'not found'
    assert deep_get(data, 'a.x', default=None) is None

def test_deep_get_empty_keys():
    """Test cases with empty or malformed keys."""
    data = {'a': {'b': 1}}

    assert deep_get(data, '', default='empty') == 'empty'
    assert deep_get(data, '.', default='dot') == 'dot'
    assert deep_get(data, '..', default='double dot') == 'double dot'

def test_deep_get_non_dict_values():
    """Test cases where intermediate values aren't dictionaries."""
    data = {'a': {'b': [1, 2, 3]}}

    assert deep_get(data, 'a.b.0', default='not list') == 'not list'
    assert deep_get(data, 'a.b.c', default='not dict') == 'not dict'

def test_deep_get_none_values():
    """Test cases with None values in the dictionary."""
    data = {'a': None, 'b': {'c': None}}

    assert deep_get(data, 'a', default='none') == 'none'
    assert deep_get(data, 'b.c', default='none') == 'none'

def test_deep_get_mixed_types():
    """Test cases with mixed types in the dictionary."""
    data = {
        'a': {
            'b': 1,
            'c': 'string',
            'd': [1, 2, 3],
            'e': {'f': True}
        }
    }

    assert deep_get(data, 'a.b') == 1
    assert deep_get(data, 'a.c') == 'string'
    assert deep_get(data, 'a.d') == [1, 2, 3]
    assert deep_get(data, 'a.e.f') is True

def test_deep_get_single_key():
    """Test cases with single key (no dots)."""
    data = {'a': 1, 'b': {'c': 2}}

    assert deep_get(data, 'a') == 1
    assert deep_get(data, 'b') == {'c': 2}

def test_deep_get_empty_dict():
    """Test cases with empty dictionary."""
    data = {}

    assert deep_get(data, 'a.b.c', default='empty') == 'empty'
    assert deep_get(data, 'a', default='empty') == 'empty'

def test_deep_get_non_string_keys():
    """Test cases where keys might not be strings (though function expects string)."""
    # This is more of a type safety test
    data = {'a': {'b': 1}}

    # Python will raise AttributeError when trying to split non-string
    with pytest.raises(AttributeError):
        deep_get(data, 123)
```

These tests cover:
1. Happy path scenarios with nested dictionaries
2. Cases where default values are returned
3. Edge cases with empty or malformed keys
4. Cases where intermediate values aren't dictionaries
5. Cases with None values in the dictionary
6. Mixed type scenarios
7. Single key cases (no dots)
8. Empty dictionary cases
9. Type safety cases (though the function expects string keys)

The tests use pytest's assertion style and include both positive and negative test cases. The `pytest.raises` context manager is used for testing error cases.
